package main

import (
	"fmt"
	"os"
	"path/filepath"
	"encoding/json"

	"github.com/spf13/cobra"
)

type Photo struct {
	Date        string `json:"date"`
	Category    string `json:"category"`
	Description string `json:"description"`
}

var archiveDir string

func main() {
	var rootCmd = &cobra.Command{
		Use:   "photomanager",
		Short: "CLI application to manage digital photography archive",
	}

	var initCmd = &cobra.Command{
		Use:   "init",
		Short: "Initialize a new photography archive",
		Run: func(cmd *cobra.Command, args []string) {
			err := os.MkdirAll(archiveDir, os.ModePerm)
			if err != nil {
				fmt.Println("Error creating archive directory:", err)
				return
			}
			fmt.Println("Archive initialized at:", archiveDir)
		},
	}

	var addCmd = &cobra.Command{
		Use:   "add",
		Short: "Add new photo entry",
		Run: func(cmd *cobra.Command, args []string) {
			var date, category, description string
			cmd.Flags().StringVarP(&date, "date", "d", "", "Photo date (YYYY-MM-DD)")
			cmd.Flags().StringVarP(&category, "category", "c", "", "Photo category")
			cmd.Flags().StringVarP(&description, "description", "e", "", "Photo description")

			err := cmd.MarkFlagRequired("date")
			if err != nil {
				fmt.Println(err)
				return
			}
			err = cmd.MarkFlagRequired("category")
			if err != nil {
				fmt.Println(err)
				return
			}
			err = cmd.MarkFlagRequired("description")
			if err != nil {
				fmt.Println(err)
				return
			}

			photo := Photo{
				Date:        date,
				Category:    category,
				Description: description,
			}

			data, err := json.Marshal(photo)
			if err != nil {
				fmt.Println("Error encoding photo metadata:", err)
				return
			}

			filePath := filepath.Join(archiveDir, fmt.Sprintf("%s.json", photo.Date))
			err = os.WriteFile(filePath, data, 0644)
			if err != nil {
				fmt.Println("Error writing photo metadata:", err)
				return
			}
			fmt.Println("Photo added:", filePath)
		},
	}

	var reportCmd = &cobra.Command{
		Use:   "report",
		Short: "Generate a summary report of all photos by category",
		Run: func(cmd *cobra.Command, args []string) {
			files, err := os.ReadDir(archiveDir)
			if err != nil {
				fmt.Println("Error reading archive directory:", err)
				return
			}

			categorySummary := make(map[string][]Photo)

			for _, file := range files {
				filePath := filepath.Join(archiveDir, file.Name())
				data, err := os.ReadFile(filePath)
				if err != nil {
					fmt.Println("Error reading file:", err)
					continue
				}

				var photo Photo
				err = json.Unmarshal(data, &photo)
				if err != nil {
					fmt.Println("Error decoding photo metadata:", err)
					continue
				}

				categorySummary[photo.Category] = append(categorySummary[photo.Category], photo)
			}

			fmt.Println("Summary Report:")
			for category, photos := range categorySummary {
				fmt.Printf("Category: %s\n", category)
				for _, photo := range photos {
					fmt.Printf("  Date: %s, Description: %s\n", photo.Date, photo.Description)
				}
			}
		},
	}

	addCmd.Flags().SortFlags = false

	rootCmd.AddCommand(initCmd, addCmd, reportCmd)
	rootCmd.PersistentFlags().StringVarP(&archiveDir, "archive", "a", "photo_archive", "Path to the archive directory")
	err := rootCmd.Execute()
	if err != nil {
		fmt.Println(err)
	}
}

#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const { Command } = require('commander');
const program = new Command();

program
  .name('count-lines')
  .description('A utility to count the number of lines in files')
  .argument('<filePaths...>', 'file paths to process')
  .action((filePaths) => {
    filePaths.forEach((filePath) => {
      const absolutePath = path.resolve(filePath);
      fs.access(absolutePath, fs.constants.R_OK, (err) => {
        if (err) {
          console.error(`Error accessing file "${filePath}": ${err.message}`);
          return;
        }
        fs.readFile(absolutePath, 'utf8', (readErr, data) => {
          if (readErr) {
            console.error(`Error reading file "${filePath}": ${readErr.message}`);
            return;
          }
          const lineCount = data.split('\n').length;
          console.log(`File: ${filePath} - Line Count: ${lineCount}`);
        });
      });
    });
  });

program.parse(process.argv);

