use std::fs;
use std::path::PathBuf;
use futures::stream::{FuturesUnordered, StreamExt};
use tokio::fs::{read_to_string, write};
use serde_json::Value;
use std::error::Error;

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    // Read JSON input containing file paths
    let input_json = fs::read_to_string("input.json")?;
    let file_paths: Vec<PathBuf> = serde_json::from_str::<Value>(&input_json)?
        .as_array()
        .unwrap_or(&[])
        .iter()
        .filter_map(|v| v.as_str().map(PathBuf::from))
        .collect();

    let mut file_read_tasks = FuturesUnordered::new();

    for path in file_paths {
        file_read_tasks.push(async move {
            match read_to_string(&path).await {
                Ok(content) => Ok(content),
                Err(err) => Err(format!("Failed to read {}: {}", path.display(), err)),
            }
        });
    }

    let mut concatenated_content = String::new();

    while let Some(result) = file_read_tasks.next().await {
        match result {
            Ok(content) => concatenated_content.push_str(&content),
            Err(err) => eprintln!("{}", err),
        }
    }

    // Write the concatenated result to the output file
    write("output.txt", concatenated_content).await?;

    Ok(())
}

