)

type User struct {
	Name  string `json:"name"`
	Email string `json:"email"`
	Age   int    `json:"age"`
}

func main() {
	// Load user data from JSON file
	jsonFile, err := os.Open("user.json")
	if err != nil {
		log.Fatalf("Failed to open JSON file: %v", err)
	}
	defer jsonFile.Close()

	byteValue, _ := ioutil.ReadAll(jsonFile)
	var user User
	if err := json.Unmarshal(byteValue, &user); err != nil {
		log.Fatalf("Failed to parse JSON file: %v", err)
	}

	// Create Resty client
	client := resty.New()

	// Send POST request
	resp, err := client.R().
		SetHeader("Content-Type", "application/json").
		SetBody(user).
		Post("https://api.example.com/users")

	if err != nil {
		log.Fatalf("Failed to send POST request: %v", err)
	}

	// Handle response
	if resp.IsError() {
		log.Fatalf("Request failed: %v", resp.Status())
	} else {
		fmt.Println("Request successful:", resp.Status())
	}
}

