  console.log('Server is running on port 3000.');
});

use tide::Request;
use tide::Response;
use tide::StatusCode;
use serde::{Deserialize, Serialize};
use serde_json::json;
use async_std::task;

#[derive(Debug, Deserialize)]
struct ProductCodes {
    codes: Vec<String>,
}

#[derive(Debug, Serialize)]
struct ValidationResponse {
    valid_codes: Vec<String>,
    invalid_codes: Vec<String>,
}

async fn handle_post(mut req: Request<()>) -> tide::Result {
    let valid_codes = vec!["PROD123", "PROD456", "PROD789"];

    let product_codes_result: Result<ProductCodes, _> = req.body_json().await;

    match product_codes_result {
        Ok(product_codes) => {
            let mut valid_codes_list = vec![];
            let mut invalid_codes_list = vec![];

            for code in product_codes.codes {
                if valid_codes.contains(&code) {
                    valid_codes_list.push(code);
                } else {
                    invalid_codes_list.push(code);
                }
            }

            let response = ValidationResponse {
                valid_codes: valid_codes_list,
                invalid_codes: invalid_codes_list,
            };

            Ok(Response::new(StatusCode::Ok)
                .body_json(&response)?)
        }
        Err(_) => Ok(Response::new(StatusCode::BadRequest)
            .body_json(&json!({"error": "Malformed JSON"}))?)
    }
}

fn main() {
    task::block_on(async {
        let mut app = tide::new();
        app.at("/validate").post(handle_post);
        app.listen("127.0.0.1:8080").await.unwrap();
    });
}

use hyper::service::{make_service_fn, service_fn};
use hyper::{Body, Request, Response, Server, Method, StatusCode};
use serde_json::{Value, json};
use std::fs;
use std::convert::Infallible;

async fn handle_request(req: Request<Body>) -> Result<Response<Body>, Infallible> {
    if req.method() == Method::GET && req.uri().path() == "/employees" {
        match fs::read_to_string("employees.json") {
            Ok(file_content) => {
                if let Ok(json_data) = serde_json::from_str::<Value>(&file_content) {
                    Ok(Response::new(Body::from(json_data.to_string())))
                } else {
                    let error_message = json!({"error": "Invalid JSON format in file"});
                    Ok(Response::builder()
                        .status(StatusCode::INTERNAL_SERVER_ERROR)
                        .body(Body::from(error_message.to_string()))
                        .unwrap())
                }
            }
            Err(_) => {
                let error_message = json!({"error": "File not found or inaccessible"});
                Ok(Response::builder()
                    .status(StatusCode::NOT_FOUND)
                    .body(Body::from(error_message.to_string()))
                    .unwrap())
            }
        }
