use tokio::net::TcpListener;
use tokio::io::{AsyncReadExt, AsyncWriteExt};
use tokio::spawn;
use std::str;
use serde_json::Value;
use serde_json::json;

async fn handle_client(mut socket: tokio::net::TcpStream) {
    let mut buf = vec![0; 1024];

    match socket.read(&mut buf).await {
        Ok(_) => {
            let request_data = str::from_utf8(&buf).unwrap_or("");
            match serde_json::from_str::<Value>(request_data) {
                Ok(json_value) if json_value.is_array() => {
                    let mut numbers: Vec<i32> = json_value.as_array()
                        .unwrap()
                        .iter()
                        .filter_map(|v| v.as_i64().map(|x| x as i32))
                        .collect();

                    numbers.sort();

                    let response = json!(numbers);
                    let response_str = response.to_string();

                    socket.write_all(response_str.as_bytes()).await.unwrap_or_else(|_| ());
                }
                _ => {
                    let error_response = json!({"error": "Invalid JSON format"});
                    let response_str = error_response.to_string();

                    socket.write_all(response_str.as_bytes()).await.unwrap_or_else(|_| ());
                }
            }
        }
        Err(_) => {
            socket.shutdown().await.unwrap_or_else(|_| ());
        }
    }
}

