import * as fs from 'fs';
import * as path from 'path';
import * as E from 'fp-ts/Either';
import * as TE from 'fp-ts/TaskEither';
import * as T from 'fp-ts/Task';
import { pipe } from 'fp-ts/function';

interface UserSettings {
  theme: string;
  notifications: boolean;
}

const settingsFilePath = path.resolve(__dirname, 'userSettings.json');

const validateSettings = (settings: any): E.Either<Error, UserSettings> => {
  if (typeof settings.theme === 'string' && typeof settings.notifications === 'boolean') {
    return E.right(settings as UserSettings);
  }
  return E.left(new Error('Invalid user settings'));
};

const readSettings = TE.tryCatch(
  () =>
    new Promise<string>((resolve, reject) => {
      fs.readFile(settingsFilePath, 'utf8', (err, data) => {
        if (err) reject(err);
        else resolve(data);
      });
    }),
  reason => new Error(String(reason))
);

const parseSettings = (data: string): E.Either<Error, UserSettings> =>
  pipe(
    E.tryCatch(() => JSON.parse(data), reason => new Error(String(reason))),
    E.chain(validateSettings)
  );

const saveSettings = (settings: UserSettings): TE.TaskEither<Error, void> =>
  TE.tryCatch(
    () =>
      new Promise<void>((resolve, reject) => {
        fs.writeFile(settingsFilePath, JSON.stringify(settings, null, 2), err => {
          if (err) reject(err);
          else resolve();
        });
      }),
    reason => new Error(String(reason))
  );

const updateUserSettings = (newSettings: Partial<UserSettings>) => 
  pipe(
    readSettings,
    TE.chain(data => TE.fromEither(parseSettings(data))),
    TE.map(currentSettings => ({ ...currentSettings, ...newSettings })),
    TE.chain(updatedSettings => saveSettings(updatedSettings))
  );

// Example usage of updateUserSettings
const task: T.Task<void> = pipe(
  updateUserSettings({ theme: 'dark' }),
  TE.fold(
    error => T.of(console.error('Error updating settings:', error)),
    _ => T.of(console.log('Settings updated successfully'))
  )
);

task();

