		return
	}
	books[book.ISBN] = book
	w.WriteHeader(http.StatusCreated)
	json.NewEncoder(w).Encode(book)
}

func listBooks(w http.ResponseWriter, r *http.Request) {
	json.NewEncoder(w).Encode(books)
