    cryptocurrency_ids: Vec<String>,
}

#[derive(Deserialize)]
struct PriceData {
    id: String,
    name: String,
    market_data: MarketData,
}

#[derive(Deserialize)]
struct MarketData {
    current_price: CurrentPrice,
}

#[derive(Deserialize)]
struct CurrentPrice {
    usd: f64,
}

#[tokio::main]
async fn main() -> Result<(), Error> {
    let config_content = fs::read_to_string("config.json").expect("Failed to read config file");
    let config: Config = serde_json::from_str(&config_content).expect("Failed to parse config file");

    for id in config.cryptocurrency_ids {
        match fetch_price(&id).await {
            Ok(Some(price_data)) => {
                println!("{}: ${:.2}", price_data.name, price_data.market_data.current_price.usd);
            }
            Ok(None) => {
                eprintln!("Cryptocurrency ID '{}' not found.", id);
            }
            Err(_) => {
                eprintln!("Failed to fetch data for ID '{}'.", id);
            }
        }
    }

    Ok(())
}

async fn fetch_price(id: &str) -> Result<Option<PriceData>, Error> {
    let url = format!("https://api.coingecko.com/api/v3/coins/{}", id);
    let response = reqwest::get(&url).await?;

    if response.status().is_success() {
        let price_data: PriceData = response.json().await?;
        Ok(Some(price_data))
    } else {
        Ok(None)
    }
}

const got = require('got');
