func main() {
	// Create a database connection.
	client, err := ent.Open("sqlite3", "file:books.db?mode=rwc")
	if err != nil {
		log.Fatalf("failed to connect to the database: %v", err)
	}
	defer client.Close()

	// Run the migrations.
	ctx := context.Background()
	if err := client.Schema.Create(ctx); err != nil {
		log.Fatalf("failed creating schema resources: %v", err)
	}

	// Example usage:
	// Add a book.
	bookID, err := CreateBook(ctx, client, "The Great Gatsby", "F. Scott Fitzgerald", 1925)
	if err != nil {
		log.Fatalf("failed creating book: %v", err)
	}
	fmt.Printf("Book created with ID: %d\n", bookID)

	// Update a book's publication year.
	err = UpdatePublicationYear(ctx, client, bookID, 1930)
	if err != nil {
		log.Fatalf("failed updating publication year: %v", err)
	}
	fmt.Println("Publication year updated")

	// Retrieve books by an author.
	books, err := GetBooksByAuthor(ctx, client, "F. Scott Fitzgerald")
	if err != nil {
		log.Fatalf("failed retrieving books by author: %v", err)
	}
	fmt.Println("Books by author:", books)

	// Delete a book.
	err = DeleteBook(ctx, client, bookID)
	if err != nil {
		log.Fatalf("failed deleting book: %v", err)
	}
	fmt.Println("Book deleted")
}

// CreateBook function to add a new book to the database.
func CreateBook(ctx context.Context, client *ent.Client, title string, author string, year int) (int, error) {
	book, err := client.Book.Create().
		SetTitle(title).
		SetAuthor(author).
		SetPublicationYear(year).
		Save(ctx)
	if err != nil {
		return 0, err
	}
	return book.ID, nil
}

// GetBooksByAuthor function to fetch books by a specific author.
func GetBooksByAuthor(ctx context.Context, client *ent.Client, author string) ([]*ent.Book, error) {
	books, err := client.Book.Query().
		Where(book.AuthorEQ(author)).
		All(ctx)
	if err != nil {
		return nil, err
	}
	return books, nil
}

// UpdatePublicationYear function to update the publication year of a book.
func UpdatePublicationYear(ctx context.Context, client *ent.Client, id int, year int) error {
	_, err := client.Book.UpdateOneID(id).
		SetPublicationYear(year).
		Save(ctx)
	return err
}

// DeleteBook function to remove a book by ID.
func DeleteBook(ctx context.Context, client *ent.Client, id int) error {
	return client.Book.DeleteOneID(id).Exec(ctx)
}

