import (
	"encoding/json"
	"errors"
	"fmt"
	"io/ioutil"
	"os"
	"path/filepath"
	"sort"
	"time"

	"github.com/urfave/cli/v2"
)

type Record struct {
	Name      string    `json:"name"`
	Timestamp time.Time `json:"timestamp"`
}

func processDirectory(dirPath string, timeFilter *time.Time) ([]string, error) {
	var names []string

	files, err := ioutil.ReadDir(dirPath)
	if err != nil {
		return nil, fmt.Errorf("error reading directory: %v", err)
	}

	for _, file := range files {
		if file.IsDir() {
			continue
		}

		ext := filepath.Ext(file.Name())
		if ext != ".json" {
			continue
		}

		filePath := filepath.Join(dirPath, file.Name())
		data, err := ioutil.ReadFile(filePath)
		if err != nil {
			return nil, fmt.Errorf("error reading file %s: %v", filePath, err)
		}

		var records []Record
		if err = json.Unmarshal(data, &records); err != nil {
			return nil, fmt.Errorf("error parsing JSON file %s: %v", filePath, err)
		}

		for _, record := range records {
			if timeFilter != nil && record.Timestamp.Before(*timeFilter) {
				continue
			}
			names = append(names, record.Name)
		}
	}

	sort.Strings(names)
	return names, nil
}

func main() {
	app := &cli.App{
		Name:  "json-processor",
		Usage: "Processes a directory of JSON files and aggregates sorted names.",
		Flags: []cli.Flag{
			&cli.StringFlag{
				Name:     "directory",
				Aliases:  []string{"d"},
				Usage:    "Path to the directory containing JSON files",
				Required: true,
			},
			&cli.StringFlag{
				Name:  "time-filter",
				Usage: "Optional time filter in RFC3339 format",
			},
		},
		Action: func(c *cli.Context) error {
			dirPath := c.String("directory")
			timeFilterStr := c.String("time-filter")

			var timeFilter *time.Time
			if timeFilterStr != "" {
				parsedTime, err := time.Parse(time.RFC3339, timeFilterStr)
				if err != nil {
					return fmt.Errorf("error parsing time filter: %v", err)
				}
				timeFilter = &parsedTime
			}

			names, err := processDirectory(dirPath, timeFilter)
			if err != nil {
				return err
			}

			for _, name := range names {
				fmt.Println(name)
			}
			return nil
		},
	}

	if err := app.Run(os.Args); err != nil {
		fmt.Println("Error:", err)
		os.Exit(1)
	}
}

