import { Controller, Route, Tags, Get, Post, Put, Delete, Body, Path } from 'tsoa';
import { Book } from '../models/Book';

let books: Book[] = [];

@Route('books')
@Tags('Books')
export class BookController extends Controller {
  @Get()
  public async getBooks(): Promise<Book[]> {
    return books;
  }

  @Get('{id}')
  public async getBook(@Path() id: number): Promise<Book> {
    const book = books.find(b => b.id === id);
    if (!book) throw new Error('Book not found');
    return book;
  }

  @Post()
  public async createBook(@Body() book: Book): Promise<Book> {
    books.push(book);
    return book;
  }

  @Put('{id}')
  public async updateBook(@Path() id: number, @Body() book: Partial<Book>): Promise<Book> {
    const existingBook = books.find(b => b.id === id);
    if (!existingBook) throw new Error('Book not found');
    Object.assign(existingBook, book);
    return existingBook;
  }

  @Delete('{id}')
  public async deleteBook(@Path() id: number): Promise<void> {
    const index = books.findIndex(b => b.id === id);
    if (index === -1) throw new Error('Book not found');
    books.splice(index, 1);
  }
}

