import (
	"log"
	"os"
	"os/exec"
	"strings"

	"github.com/go-co-op/gocron"
)

func getDiskUsage() (string, error) {
	cmd := exec.Command("df", "--output=pcent", "/")
	output, err := cmd.Output()
	if err != nil {
		return "", err
	}
	result := strings.Split(string(output), "\n")
	if len(result) > 1 {
		return strings.TrimSpace(result[1]), nil
	}
	return "", nil
}

func logDiskUsage() {
	usage, err := getDiskUsage()
	if err != nil {
		log.Printf("Failed to get disk usage: %v\n", err)
		return
	}

	file, err := os.OpenFile("disk_usage.log", os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		log.Printf("Failed to open log file: %v\n", err)
		return
	}
	defer file.Close()

	_, err = file.WriteString(usage + "\n")
	if err != nil {
		log.Printf("Failed to write to log file: %v\n", err)
	}
}

func main() {
	scheduler := gocron.NewScheduler()

	_, err := scheduler.Every(10).Minutes().Do(logDiskUsage)
	if err != nil {
		log.Fatalf("Failed to schedule task: %v\n", err)
		return
	}

	scheduler.StartBlocking()
}

