use actix_web::{web, App, HttpServer, HttpResponse};
use serde::{Deserialize, Serialize};
use sqlx::{Pool, Postgres, postgres::PgPoolOptions};
use bcrypt::{hash, verify};
use uuid::Uuid;

#[derive(Serialize, Deserialize)]
struct User {
    username: String,
    password: String,
}

#[derive(Serialize, Deserialize)]
struct DbUser {
    id: Uuid,
    username: String,
    hashed_password: String,
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let database_url = "postgres://user:password@localhost/auth_db";
    let pool = PgPoolOptions::new()
        .max_connections(5)
        .connect(database_url)
        .await
        .expect("Failed to connect to the database");

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(pool.clone()))
            .route("/register", web::post().to(register_user))
            .route("/login", web::post().to(login_user))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}

async fn register_user(
    pool: web::Data<Pool<Postgres>>, 
    user: web::Json<User>
) -> HttpResponse {
    let hashed_password = match hash(&user.password, bcrypt::DEFAULT_COST) {
        Ok(h) => h,
        Err(_) => return HttpResponse::InternalServerError().finish(),
    };

    let query = sqlx::query!(
        "INSERT INTO users (id, username, hashed_password) VALUES ($1, $2, $3)",
        Uuid::new_v4(),
        user.username,
        hashed_password
    );

    match query.execute(pool.get_ref()).await {
        Ok(_) => HttpResponse::Ok().json("User registered"),
        Err(_) => HttpResponse::InternalServerError().json("Database error"),
    }
}

async fn login_user(
    pool: web::Data<Pool<Postgres>>, 
    user: web::Json<User>
) -> HttpResponse {
    let query = sqlx::query_as!(
        DbUser,
        "SELECT id, username, hashed_password FROM users WHERE username = $1",
        user.username
    );

    let db_user = match query.fetch_one(pool.get_ref()).await {
        Ok(user) => user,
        Err(_) => return HttpResponse::Unauthorized().json("Invalid username or password"),
    };

    if verify(&user.password, &db_user.hashed_password).unwrap_or(false) {
        HttpResponse::Ok().json("Login successful")
    } else {
        HttpResponse::Unauthorized().json("Invalid username or password")
    }
}

