package main

import (
	"fmt"
	"log"
	"os"

	"gorm.io/driver/postgres"
	"gorm.io/gorm"
	"gorm.io/gorm/logger"
)

type Book struct {
	ID       uint   `gorm:"primaryKey"`
	Title    string `gorm:"not null"`
	Author   string `gorm:"not null"`
	ISBN     string `gorm:"not null"`
	Quantity int    `gorm:"not null"`
}

var db *gorm.DB

func initDatabase() {
	var err error
	dsn := "host=localhost user=yourusername password=yourpassword dbname=bookstore port=5432 sslmode=disable TimeZone=UTC"
	db, err = gorm.Open(postgres.Open(dsn), &gorm.Config{
		Logger: logger.Default.LogMode(logger.Info),
	})
	if err != nil {
		log.Fatalf("Failed to connect to database: %v\n", err)
	}
	db.AutoMigrate(&Book{})
}

func createBook(title, author, isbn string, quantity int) {
	book := Book{Title: title, Author: author, ISBN: isbn, Quantity: quantity}
	result := db.Create(&book)
	logAction("Create", result.Error)
}

func updateBook(id uint, title, author, isbn string, quantity int) {
	var book Book
	result := db.First(&book, id)
	if result.Error != nil {
		logAction("Update (Fetch)", result.Error)
		return
	}
	book.Title = title
	book.Author = author
	book.ISBN = isbn
	book.Quantity = quantity
	result = db.Save(&book)
	logAction("Update", result.Error)
}

func deleteBook(id uint) {
	result := db.Delete(&Book{}, id)
	logAction("Delete", result.Error)
}

func fetchBooks() {
	var books []Book
	result := db.Find(&books)
	logAction("Fetch", result.Error)
	fmt.Println("Books in inventory:")
	for _, book := range books {
		fmt.Printf("ID: %d | Title: %s | Author: %s | ISBN: %s | Quantity: %d\n", book.ID, book.Title, book.Author, book.ISBN, book.Quantity)
	}
}

func logAction(action string, err error) {
	if err != nil {
		log.Printf("Error during %s action: %v\n", action, err)
	} else {
		log.Printf("%s action completed successfully\n", action)
	}
}

func main() {
	initDatabase()
	if len(os.Args) < 2 {
		fmt.Println("Usage: go run main.go <command> [arguments]")
		return
	}

	command := os.Args[1]
	switch command {
	case "create":
		if len(os.Args) < 6 {
			fmt.Println("Usage: go run main.go create <title> <author> <isbn> <quantity>")
			return
		}
		createBook(os.Args[2], os.Args[3], os.Args[4], atoi(os.Args[5]))
	case "update":
		if len(os.Args) < 7 {
			fmt.Println("Usage: go run main.go update <id> <title> <author> <isbn> <quantity>")
			return
		}
		updateBook(atoi(os.Args[2]), os.Args[3], os.Args[4], os.Args[5], atoi(os.Args[6]))
	case "delete":
		if len(os.Args) < 3 {
			fmt.Println("Usage: go run main.go delete <id>")
			return
		}
		deleteBook(atoi(os.Args[2]))
	case "fetch":
		fetchBooks()
	default:
		fmt.Println("Unknown command. Available commands: create, update, delete, fetch")
	}
}

