package main

import (
	"encoding/csv"
	"fmt"
	"os"
	"strconv"

	"github.com/asynkron/protoactor-go/actor"
)

type TradingData struct {
	Firm       string
	StockPrice float64
	Volume     int
}

type ProcessStockData struct {
	Data TradingData
}

type FirmActor struct{}
type AggregatorActor struct {
	TotalVolume    int
	HighestPrice   float64
	PendingFirms   int
	ResponseChan   chan struct{}
}

func (f *FirmActor) Receive(ctx actor.Context) {
	switch msg := ctx.Message().(type) {
	case ProcessStockData:
		// Simulate processing
		ctx.Send(ctx.Parent(), msg.Data)
	}
}

func (a *AggregatorActor) Receive(ctx actor.Context) {
	switch msg := ctx.Message().(type) {
	case TradingData:
		a.TotalVolume += msg.Volume
		if msg.StockPrice > a.HighestPrice {
			a.HighestPrice = msg.StockPrice
		}
		a.PendingFirms--
		if a.PendingFirms == 0 {
			close(a.ResponseChan)
		}
	case *actor.Started:
		a.ResponseChan = make(chan struct{})
	}
}

func main() {
	system := actor.NewActorSystem()

	// Create Aggregator Actor
	propsAggregator := actor.PropsFromProducer(func() actor.Actor {
		return &AggregatorActor{}
	})
	aggregatorPID := system.Root.Spawn(propsAggregator)

	// Create Firm Actors
	const NumberOfFirms = 5
	firmActors := make([]*actor.PID, NumberOfFirms)
	for i := 0; i < NumberOfFirms; i++ {
		propsFirm := actor.PropsFromProducer(func() actor.Actor {
			return &FirmActor{}
		})
		firmActors[i] = system.Root.Spawn(propsFirm)
	}

	// Read and dispatch CSV data
	file, err := os.Open("trading_data.csv")
	if err != nil {
		fmt.Println("Error reading file:", err)
		return
	}
	defer file.Close()

	reader := csv.NewReader(file)
	records, err := reader.ReadAll()
	if err != nil {
		fmt.Println("Error parsing CSV:", err)
		return
	}

	system.Root.Send(aggregatorPID, actor.Started{})
	for _, record := range records {
		if len(record) < 3 {
			fmt.Println("Incomplete record, skipping:", record)
			continue
		}

		firm := record[0]
		price, err := strconv.ParseFloat(record[1], 64)
		if err != nil {
			fmt.Println("Invalid stock price, skipping:", record)
			continue
		}
		volume, err := strconv.Atoi(record[2])
		if err != nil {
			fmt.Println("Invalid volume, skipping:", record)
			continue
		}

		data := TradingData{Firm: firm, StockPrice: price, Volume: volume}
		system.Root.Send(firmActors[volume%NumberOfFirms], ProcessStockData{Data: data})
	}

	// Wait for aggregation results
	aggregator := system.Root.GetActor(aggregatorPID).(*AggregatorActor)
	aggregator.PendingFirms = len(records)
	<-aggregator.ResponseChan

	fmt.Printf("Total Trading Volume: %d\n", aggregator.TotalVolume)
	fmt.Printf("Highest Stock Price: %.2f\n", aggregator.HighestPrice)
}

