import axios from 'axios';
import { match, P } from 'ts-pattern';

// Define types for SWAPI response
type Character = {
  name: string;
  gender: string;
  species: string;
};

// Function to fetch character data
async function fetchCharacterData() {
  try {
    const response = await axios.get('https://swapi.dev/api/people/');
    const characters = response.data.results;

    characters.forEach((character: any) => {
      match(character)
        .with(
          { name: P.string, gender: P.string, species: P.array },
          (c) => {
            const formattedCharacter: Character = {
              name: c.name,
              gender: c.gender,
              species: c.species.join(', '),
            };
            console.log(formattedCharacter);
          }
        )
        .with(P.shape({ name: P.string, gender: P.string }), (c) => {
          const formattedCharacter: Character = {
            name: c.name,
            gender: c.gender,
            species: 'Unknown',
          };
          console.log(formattedCharacter);
        })
        .otherwise(() => {
          console.error('Unexpected response schema:', character);
        });
    });
  } catch (error) {
    match(error)
      .with({ response: P.object }, (e) => {
        console.error('API Error:', e.response.status, e.response.data);
      })
      .otherwise(() => {
        console.error('Unknown Error:', error);
      });
  }
}

// Fetch and log Star Wars characters
fetchCharacterData();

