package main

import (
	"fmt"
	"sync"
)

func concurrentSum[T int | float64](arr []T) T {
	var wg sync.WaitGroup
	result := T(0)
	mu := sync.Mutex{}

	for _, v := range arr {
		wg.Add(1)
		go func(value T) {
			defer wg.Done()
			mu.Lock()
			result += value
			mu.Unlock()
		}(v)
	}

	wg.Wait()
	return result
}

func main() {
	numbers := []int{1, 2, 3, 4, 5}
	sum := concurrentSum(numbers)
	fmt.Println("Sum:", sum)
}

import requests
import json
import sys
import logging
import time

# Configure logging
logging.basicConfig(level=logging.INFO)

# Check Python version
if sys.version_info.major < 3:
    raise Exception("This script requires Python 3.")

# Configurable API endpoint
API_ENDPOINT = 'https://api.weatherapi.com/v1/current.json?key=YOUR_API_KEY&q=London'

def get_weather_data(api_endpoint):
    headers = {
        'User-Agent': f"Python/{sys.version_info.major}.{sys.version_info.minor}"
    }
    retries = 3
    for attempt in range(retries):
        try:
            response = requests.get(api_endpoint, headers=headers)
            response.raise_for_status()
            data = response.json()
            return data
        except requests.exceptions.HTTPError as http_err:
            logging.error(f"HTTP error occurred: {http_err}")
        except requests.exceptions.ConnectionError as conn_err:
            logging.error(f"Connection error occurred: {conn_err}")
        except requests.exceptions.Timeout as timeout_err:
            logging.error(f"Timeout error occurred: {timeout_err}")
        except requests.exceptions.RequestException as req_err:
            logging.error(f"Request exception occurred: {req_err}")
        logging.info(f"Retrying {attempt + 1}/{retries}...")
        time.sleep(3)
    return {}

def parse_weather_data(data):
    try:
        temperature = data['current']['temp_c']
        humidity = data['current']['humidity']
        weather_condition = data['current']['condition']['text']
        formatted_output = (
            f"Temperature: {temperature}°C\n"
            f"Humidity: {humidity}%\n"
            f"Weather Condition: {weather_condition}\n"
        )
        return formatted_output
    except KeyError as e:
        logging.error(f"Key error occurred: {e}")
        return "Failed to parse weather data"

if __name__ == '__main__':
    weather_data = get_weather_data(API_ENDPOINT)
    formatted_weather = parse_weather_data(weather_data)
    print(formatted_weather)
